let RUNICO_LOCALE = 'en';
function setRunicoLocale(code) {
  RUNICO_LOCALE = (code && RUNICO_STRINGS[code]) ? code : 'en';
}
function getRunicoLocale() { return RUNICO_LOCALE; }
function t(key, vars) {
  const dict = RUNICO_STRINGS[RUNICO_LOCALE] || RUNICO_STRINGS.en;
  let s = (dict && dict[key] != null) ? dict[key]
        : (RUNICO_STRINGS.en[key] != null ? RUNICO_STRINGS.en[key] : key);
  if (vars) for (const k in vars) s = s.split('{' + k + '}').join(String(vars[k]));
  return s;
}
// Plural-aware: uses key + '_one' when count === 1 (and that variant exists).
function tp(key, count, vars) {
  const useOne = count === 1 && RUNICO_STRINGS.en[key + '_one'] != null;
  return t(useOne ? key + '_one' : key, vars);
}
// Expose on window so the Babel-compiled app.jsx can reference these globals.
window.RUNICO_STRINGS = RUNICO_STRINGS;
window.setRunicoLocale = setRunicoLocale;
window.getRunicoLocale = getRunicoLocale;
window.t = t;
window.tp = tp;
